export const iconCategories = ["class","monster","status","spell-school","room","item","loot","ui"] as const;
export type IconCategory = typeof iconCategories[number];

export function getIconKeys(category: IconCategory): string[] {
  return Object.keys(gameIcons).filter(k => k.startsWith(category + "/"));
}
